={{
  (() => {
    const plan = $json.body.submission.questions.find(q => q.name === "Choose Your Plan").value;
    const start = new Date($json.body.submission.submissionTime);
    if (plan.includes("Weekly")) start.setDate(start.getDate() + 7);
    else if (plan.includes("Monthly")) start.setMonth(start.getMonth() + 1);
    else if (plan.includes("3 Month")) start.setMonth(start.getMonth() + 3);
    else if (plan.includes("6 Month")) start.setMonth(start.getMonth() + 6);
    return start.toLocaleDateString('en-GB', { year: 'numeric', month: 'short', day: '2-digit' }).replace(/ /g, '-');
  })()
}}

