const airtableRecord = $input.first();

// Get plan from airtable current record
const fullName = airtableRecord.json.fields['Full Name'];
const email = airtableRecord.json.fields['Email'];

// Get plan from airtable 
const planRaw = airtableRecord.json.fields['Plan'];
const plan = planRaw;

const today = DateTime.now().setZone('Africa/Lagos');

let newEndDate;
if (plan.includes('Weekly')) {
  newEndDate = today.plus({ weeks: 1 });
} else if (plan.includes('1 Months')) {
  newEndDate = today.plus({ months: 1 });
} else if (plan.includes('3 Months')) {
  newEndDate = today.plus({ months: 3 });
} else {
  newEndDate = today.plus({ months: 6 });
}

return [{
  json: {
    recordId: airtableRecord.json.id,
    fullName: fullName,
    firstName: fullName.split(' ')[0],
    email: email,
    plan: plan,
    newStartDate: today.toFormat('yyyy-MM-dd'),
    newEndDate: newEndDate.toFormat('yyyy-MM-dd'),
    newStartDateFormatted: today.toFormat('dd MMMM yyyy'),
    newEndDateFormatted: newEndDate.toFormat('dd MMMM yyyy'),
    totalCheckins: airtableRecord.json.fields['Total Check-ins'] ?? 0
  }
}];

